  1	import {
  2	  Button,
  3	  Divider,
  4	  ExpandableSection,
  5	  Flex,
  6	  FlexItem,
  7	  Label,
  8	} from "@patternfly/react-core";
  9	
 10	import { FieldArray, FieldArrayRenderProps, useField } from "formik";
 11	import * as React from "react";
 12	import {
 13	  getEmptyRemediationTemplate,
 14	  getSortedRemediators,
 15	} from "../../../../data/remediator";
 16	import { Remediator } from "../../../../data/types";
 17	import { useNodeHealthCheckTranslation } from "../../../../localization/useNodeHealthCheckTranslation";
 18	import RemediatorField from "./RemediatorField";
 19	import { DragDrop, Draggable, Droppable } from "@patternfly/react-core";
 20	import { WithRemoveButton } from "../../../shared/WithRemoveButton";
 21	import { GripVerticalIcon, InfoCircleIcon } from "@patternfly/react-icons";
 22	import { getDurationHelptext } from "../../../../copiedFromConsole/utils/durationUtils";
 23	import HelpIcon from "../../../shared/HelpIcon";
 24	import AddMoreButton from "../../../shared/AddMoreButton";
 25	import NumberSpinnerField from "../../../shared/NumberSpinnerField";
 26	import { useDebounce } from "../../../../copiedFromConsole/hooks/useDebounce";
 27	import InputField from "../../../../copiedFromConsole/formik-fields/InputField";
 28	import { isEqual } from "lodash-es";
 29	
 30	const ToggleContent = ({
 31	  fieldName,
 32	  isExpanded,
 33	}: {
 34	  fieldName: string;
 35	  isExpanded: boolean;
 36	}) => {
 37	  const [{ value }, { error }] = useField<Remediator>(fieldName);
 38	  const { t } = useNodeHealthCheckTranslation();
 39	  return (
 40	    <Flex alignItems={{ default: "alignItemsFlexStart" }}>
 41	      <FlexItem>
 42	        {value?.template?.name
 43	          ? value?.template?.name
 44	          : t("Name of remediation template")}
 45	      </FlexItem>
 46	      {error && !isExpanded && (
 47	        <FlexItem>
 48	          <Label color="red" icon={<InfoCircleIcon />} variant="outline">
 49	            {t("Missing information")}
 50	          </Label>
 51	        </FlexItem>
 52	      )}
 53	    </Flex>
 54	  );
 55	};
 56	
 57	const TimeoutField = ({ fieldName }: { fieldName: string }) => {
 58	  const { t } = useNodeHealthCheckTranslation();
 59	  return (
 60	    <InputField
 61	      name={fieldName}
 62	      label={t("Timeout")}
 63	      required
 64	      helpText={getDurationHelptext(t)}
 65	      labelIcon={
 66	        <HelpIcon
 67	          helpText={t(
 68	            "The timeout field determines when the next remediation template is invoked."
 69	          )}
 70	        />
 71	      }
 72	    />
 73	  );
 74	};
 75	
 76	const OrderField = ({
 77	  fieldName,
 78	  onChange,
 79	}: {
 80	  fieldName: string;
 81	  onChange: () => void;
 82	}) => {
 83	  const { t } = useNodeHealthCheckTranslation();
 84	  return (
 85	    <NumberSpinnerField
 86	      name={fieldName}
 87	      required
 88	      label={t("Order")}
 89	      labelIcon={
 90	        <HelpIcon
 91	          helpText={t(
 92	            "The order field determines the order in which the remediations are invoked. The lower order number is invoked earlier."
 93	          )}
 94	        />
 95	      }
 96	      onBlur={onChange}
 97	    />
 98	  );
 99	};
100	
101	const SingleRemediatorField = ({
102	  index,
103	  remove,
104	  fieldName,
105	  onOrderChanged,
106	  isExpanded,
107	  toggleExpand,
108	  isRemoveDisabled,
109	}: {
110	  remove: (index: number) => void;
111	  index: number;
112	  fieldName: string;
113	  onOrderChanged: () => void;
114	  isExpanded: boolean;
115	  toggleExpand: (index: number) => void;
116	  isRemoveDisabled: boolean;
117	}) => {
118	  return (
119	    <>
120	      <WithRemoveButton
121	        onClick={() => remove(index)}
122	        isDisabled={isRemoveDisabled}
123	        dataTest={"remove-remediator-button"}
124	      >
125	        <Flex
126	          alignItems={{ default: "alignItemsFlexStart" }}
127	          flexWrap={{ default: "nowrap" }}
128	        >
129	          <FlexItem
130	            spacer={{ default: "spacerSm" }}
131	            className="pf-c-expandable-section"
132	          >
133	            <Button
134	              icon={<GripVerticalIcon />}
135	              style={{
136	                padding:
137	                  "var(--pf-c-expandable-section__toggle--PaddingTop) 0 var(--pf-c-expandable-section__toggle--PaddingBottom) 0",
138	              }}
139	              variant="plain"
140	            />
141	          </FlexItem>
142	          <FlexItem grow={{ default: "grow" }}>
143	            <ExpandableSection
144	              toggleContent={
145	                <ToggleContent fieldName={fieldName} isExpanded={isExpanded} />
146	              }
147	              isIndented
148	              isExpanded={isExpanded}
149	              onToggle={() => toggleExpand(index)}
150	            >
151	              <>
152	                <RemediatorField fieldName={`${fieldName}`} />
153	                <TimeoutField fieldName={`${fieldName}.timeout`} />
154	                <OrderField
155	                  fieldName={`${fieldName}.order`}
156	                  onChange={onOrderChanged}
157	                />
158	              </>
159	            </ExpandableSection>
160	          </FlexItem>
161	        </Flex>
162	      </WithRemoveButton>
163	      <Divider />
164	    </>
165	  );
166	};
167	
168	interface SourceType {
169	  droppableId: string;
170	  index: number;
171	}
172	type DestinationType = SourceType;
173	
174	const reorder = (list: Remediator[], startIndex: number, endIndex: number) => {
175	  const result = list;
176	  const [removed] = result.splice(startIndex, 1);
177	  result.splice(endIndex, 0, removed);
178	  return result;
179	};
180	
181	const getExpanded = (
182	  remediators: Remediator[],
183	  expandLast?: boolean
184	): Record<number, boolean> => {
185	  const ret: Record<number, boolean> = {};
186	  for (let i = 0; i < remediators.length; ++i) {
187	    ret[remediators[i].id] = false;
188	  }
189	  if (expandLast) {
190	    ret[remediators[remediators.length - 1].id] = true;
191	  }
192	  return ret;
193	};
194	
195	const RemediatorsArrayFieldContent = ({
196	  push,
197	  remove,
198	  fieldName,
199	}: FieldArrayRenderProps & {
200	  fieldName: string;
201	}) => {
202	  const [{ value: remediators }, , { setValue: setRemediators }] =
203	    useField<Remediator[]>(fieldName);
204	  const { t } = useNodeHealthCheckTranslation();
205	
206	  const [expanded, setExpanded] = React.useState<Record<number, boolean>>(
207	    getExpanded(remediators || [], remediators?.length === 1)
208	  );
209	
210	  const onOrderFieldChange = (id: number) => {
211	    const newRemediators = getSortedRemediators(remediators);
212	    if (!isEqual(newRemediators, remediators)) {
213	      setRemediators(getSortedRemediators(remediators));
214	      setExpanded({ ...getExpanded(remediators), [id]: true });
215	    }
216	  };
217	
218	  const debounce = useDebounce(onOrderFieldChange, 300);
219	
220	  const onDrop = (source: SourceType, dest: DestinationType) => {
221	    debounce.cancel();
222	    if (dest) {
223	      const newItems = reorder(remediators, source.index, dest.index).map(
224	        (r, idx) => ({ ...r, order: idx })
225	      );
226	      setRemediators(newItems);
227	      return true;
228	    }
229	    return false;
230	  };
231	
232	  const onAdd = () => {
233	    const prevRemediatorOrder = remediators[remediators.length - 1]?.order;
234	    const newRemediator: Remediator = {
235	      template: getEmptyRemediationTemplate(),
236	      order: (prevRemediatorOrder || 0) + 1,
237	      id: Math.random(),
238	    };
239	    setExpanded(getExpanded([...remediators, newRemediator], true));
240	    push(newRemediator);
241	  };
242	
243	  return (
244	    <>
245	      <DragDrop onDrop={onDrop}>
246	        <Droppable>
247	          <>
248	            {remediators?.map((_remediator, index) => (
249	              <Draggable key={index}>
250	                <SingleRemediatorField
251	                  key={_remediator.id}
252	                  index={index}
253	                  remove={remove}
254	                  fieldName={`${fieldName}[${index}]`}
255	                  // eslint-disable-next-line @typescript-eslint/no-unsafe-return
256	                  onOrderChanged={() => debounce(_remediator.id)}
257	                  isExpanded={expanded[_remediator.id]}
258	                  toggleExpand={() =>
259	                    setExpanded({
260	                      ...expanded,
261	                      [_remediator.id]: !expanded[_remediator.id],
262	                    })
263	                  }
264	                  isRemoveDisabled={remediators.length === 1}
265	                />
266	              </Draggable>
267	            ))}
268	          </>
269	        </Droppable>
270	      </DragDrop>
271	      <AddMoreButton onClick={onAdd} dataTest="add-remediator-button">
272	        {t("Add more")}
273	      </AddMoreButton>
274	    </>
275	  );
276	};
277	
278	const RemediatorsArrayField = () => {
279	  const fieldName = "formData.escalatingRemediations";
280	  return (
281	    <FieldArray name={fieldName} validateOnChange={false}>
282	      {(props) => {
283	        return (
284	          <RemediatorsArrayFieldContent fieldName={fieldName} {...props} />
285	        );
286	      }}
287	    </FieldArray>
288	  );
289	};
290	
291	export default RemediatorsArrayField;

